+template <typename KTraits>
+__device__ __forceinline__ void init_states_(float* o_frag, float* m, float* d, float* o_scale) {
+#pragma unroll
+  for (uint32_t reg_id = 0; reg_id < KTraits::NUM_REGS_O_FRAG; ++reg_id) {
+    o_frag[reg_id] = 0.f;
+  }
+
+#pragma unroll
+  for (uint32_t j = 0; j < 2; ++j) {
+    m[j] = -math::inf;
+    d[j] = 1.f;
+    o_scale[j] = 1.f;
+  }
+}
